import java.util.HashMap;

public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class Solution {
    private HashMap<Integer, Integer> indexMap;

    private TreeNode buildTree(int[] inorder, int[] postorder, int in_left, int in_right, int post_root) {
        if (in_left > in_right)
            return null;

        TreeNode root = new TreeNode(postorder[post_root]);

        int inorder_root_index = indexMap.get(root.val);
        int left_tree_size = inorder_root_index - in_left;

        root.left = buildTree(inorder, postorder, in_left, inorder_root_index - 1, post_root - 1 - in_right + inorder_root_index);
        root.right = buildTree(inorder, postorder, inorder_root_index + 1, in_right, post_root - 1);

        return root;
    }

    public TreeNode buildTree(int[] inorder, int[] postorder) {
        int n = inorder.length;
        indexMap = new HashMap<>();
        for (int i = 0; i < n; ++i) {
            indexMap.put(inorder[i], i);
        }
        return buildTree(inorder, postorder, 0, n - 1, n - 1);
    }
}
